    #[test]
    fn test_build_single_crate() {
        let dir = tempfile::tempdir().unwrap();
        let root = dir.path();

        // Create a mini crate
        fs::write(
            root.join("Cargo.toml"),
            "[package]\nname = \"my-crate\"\nversion = \"0.1.0\"\nedition = \"2021\"\n",
        ).unwrap();
        fs::create_dir_all(root.join("src")).unwrap();
        fs::write(root.join("src/lib.rs"), "mod config;\nmod utils;\n").unwrap();
        fs::write(root.join("src/config.rs"), "pub struct Config {}\n").unwrap();
        fs::create_dir_all(root.join("src/utils")).unwrap();
        fs::write(root.join("src/utils/mod.rs"), "mod helpers;\n").unwrap();
        fs::write(root.join("src/utils/helpers.rs"), "pub fn help() {}\n").unwrap();

        let map = RustModuleMap::build(root);

        assert_eq!(map.module_to_file.get("my_crate"), Some(&"src/lib.rs".to_string()));
        assert_eq!(map.module_to_file.get("my_crate::config"), Some(&"src/config.rs".to_string()));
        assert!(map.module_to_file.contains_key("my_crate::utils"));
        assert!(map.module_to_file.contains_key("my_crate::utils::helpers"));
    }

